import{_ as e,c as a,o as p,a as t}from"./app.3237b7cc.js";const g=JSON.parse('{"title":"\u7985\u4FEE\u7684\u6838\u5FC3\uFF1A\u89C9\u7167\u3001\u5984\u5FF5\u4E0E\u65E0\u5FF5\u65E0\u89C9","description":"\u4ECE\u300C\u6211\u60F3\u73A9\u300D\u7684\u7985\u673A\u5230\u300C\u65E0\u5FF5\u65E0\u89C9\uFF0C\u5FF5\u65F6\u89C9\u77E5\u300D\u7684\u4FEE\u884C\u5FC3\u6CD5","frontmatter":{"title":"\u7985\u4FEE\u7684\u6838\u5FC3\uFF1A\u89C9\u7167\u3001\u5984\u5FF5\u4E0E\u65E0\u5FF5\u65E0\u89C9","description":"\u4ECE\u300C\u6211\u60F3\u73A9\u300D\u7684\u7985\u673A\u5230\u300C\u65E0\u5FF5\u65E0\u89C9\uFF0C\u5FF5\u65F6\u89C9\u77E5\u300D\u7684\u4FEE\u884C\u5FC3\u6CD5","date":"2026-04-13T00:00:00.000Z"},"headers":[{"level":2,"title":"\u95EE\u9898\u80CC\u666F","slug":"\u95EE\u9898\u80CC\u666F","link":"#\u95EE\u9898\u80CC\u666F","children":[]},{"level":2,"title":"\u7985\u673A\uFF1A\u8FF7\u4E0E\u609F\u7684\u5206\u91CE","slug":"\u7985\u673A-\u8FF7\u4E0E\u609F\u7684\u5206\u91CE","link":"#\u7985\u673A-\u8FF7\u4E0E\u609F\u7684\u5206\u91CE","children":[]},{"level":2,"title":"\u89C9\u7167\u4E0D\u662F\u76D1\u63A7","slug":"\u89C9\u7167\u4E0D\u662F\u76D1\u63A7","link":"#\u89C9\u7167\u4E0D\u662F\u76D1\u63A7","children":[]},{"level":2,"title":"\u5984\u5FF5\u4E0E\u89C9\u7167\u7684\u5173\u7CFB","slug":"\u5984\u5FF5\u4E0E\u89C9\u7167\u7684\u5173\u7CFB","link":"#\u5984\u5FF5\u4E0E\u89C9\u7167\u7684\u5173\u7CFB","children":[]},{"level":2,"title":"\u65E0\u5FF5\u672C\u8EAB\u4E5F\u662F\u4E00\u4E2A\u76F8","slug":"\u65E0\u5FF5\u672C\u8EAB\u4E5F\u662F\u4E00\u4E2A\u76F8","link":"#\u65E0\u5FF5\u672C\u8EAB\u4E5F\u662F\u4E00\u4E2A\u76F8","children":[]},{"level":2,"title":"\u65E0\u5FF5\u65E0\u89C9\uFF0C\u80FD\u6240\u53CC\u4EA1","slug":"\u65E0\u5FF5\u65E0\u89C9-\u80FD\u6240\u53CC\u4EA1","link":"#\u65E0\u5FF5\u65E0\u89C9-\u80FD\u6240\u53CC\u4EA1","children":[]},{"level":2,"title":"\u4FEE\u884C\uFF0C\u4ECE\u8FD9\u91CC\u5F00\u59CB","slug":"\u4FEE\u884C-\u4ECE\u8FD9\u91CC\u5F00\u59CB","link":"#\u4FEE\u884C-\u4ECE\u8FD9\u91CC\u5F00\u59CB","children":[]},{"level":2,"title":"\u603B\u7ED3","slug":"\u603B\u7ED3","link":"#\u603B\u7ED3","children":[]}],"relativePath":"posts/zen-awareness-emptiness.md"}'),r={name:"posts/zen-awareness-emptiness.md"},i=t('<h1 id="\u7985\u4FEE\u7684\u6838\u5FC3-\u89C9\u7167\u3001\u5984\u5FF5\u4E0E\u65E0\u5FF5\u65E0\u89C9" tabindex="-1">\u7985\u4FEE\u7684\u6838\u5FC3\uFF1A\u89C9\u7167\u3001\u5984\u5FF5\u4E0E\u65E0\u5FF5\u65E0\u89C9 <a class="header-anchor" href="#\u7985\u4FEE\u7684\u6838\u5FC3-\u89C9\u7167\u3001\u5984\u5FF5\u4E0E\u65E0\u5FF5\u65E0\u89C9" aria-hidden="true">#</a></h1><blockquote><p>\u5F53\u4F60\u95EE\u300C\u6211\u60F3\u73A9\uFF0C\u548C\u53D1\u73B0\u6211\u60F3\u73A9\u3002\u7985\u673A\u5728\u54EA\u91CC\uFF1F\u300D\u65F6\uFF0C\u4F60\u5DF2\u7ECF\u89E6\u53CA\u4E86\u7985\u5B97\u4FEE\u884C\u7684\u6838\u5FC3\u79D8\u5BC6\u3002</p></blockquote><h2 id="\u95EE\u9898\u80CC\u666F" tabindex="-1">\u95EE\u9898\u80CC\u666F <a class="header-anchor" href="#\u95EE\u9898\u80CC\u666F" aria-hidden="true">#</a></h2><p>\u5728\u65E5\u5E38\u4FEE\u884C\u4E2D\uFF0C\u6211\u4EEC\u5E38\u5E38\u4F1A\u9047\u5230\u4E00\u4E2A\u770B\u4F3C\u7B80\u5355\u5374\u6DF1\u5965\u7684\u95EE\u9898\uFF1A\u5F53\u5FC3\u91CC\u5192\u51FA\u300C\u6211\u60F3\u73A9\u6E38\u620F\u300D\u300C\u6211\u60F3\u5237\u77ED\u89C6\u9891\u300D\u300C\u6211\u60F3\u5077\u61D2\u300D\u7684\u5FF5\u5934\u65F6\uFF0C\u6211\u4EEC\u8BE5\u5982\u4F55\u9762\u5BF9\uFF1F</p><p>\u5F88\u591A\u4EBA\u7B2C\u4E00\u53CD\u5E94\u662F\u538B\u5236\u8FD9\u4E9B\u5FF5\u5934\uFF0C\u544A\u8BC9\u81EA\u5DF1\u300C\u4E0D\u5E94\u8BE5\u60F3\u300D\u300C\u8981\u4E13\u6CE8\u300D\u300C\u8981\u4FEE\u884C\u300D\u3002\u4F46\u8FD9\u79CD\u5BF9\u6297\u672C\u8EAB\u5C31\u662F\u53E6\u4E00\u79CD\u6267\u7740\uFF0C\u751A\u81F3\u8BA9\u4EBA\u66F4\u52A0\u75B2\u60EB\u3002\u6211\u4EEC\u4E0D\u7981\u8981\u95EE\uFF1A\u4FEE\u884C\u7684\u771F\u6B63\u65B9\u5411\u5728\u54EA\u91CC\uFF1F\u89C9\u7167\u4E0E\u5984\u5FF5\u5230\u5E95\u662F\u4EC0\u4E48\u5173\u7CFB\uFF1F</p><h2 id="\u7985\u673A-\u8FF7\u4E0E\u609F\u7684\u5206\u91CE" tabindex="-1">\u7985\u673A\uFF1A\u8FF7\u4E0E\u609F\u7684\u5206\u91CE <a class="header-anchor" href="#\u7985\u673A-\u8FF7\u4E0E\u609F\u7684\u5206\u91CE" aria-hidden="true">#</a></h2><p>\u300C\u6211\u60F3\u73A9\u300D\u662F\u4E00\u79CD\u4E3B\u52A8\u7684\u6B32\u671B\uFF0C\u6709\u4E00\u4E2A\u300C\u6211\u300D\u5728\u53D1\u8D77\u8FD9\u4E2A\u5FF5\u5934\u3002\u6B64\u65F6\u300C\u6211\u300D\u4E0E\u300C\u73A9\u300D\u4E8C\u5143\u5BF9\u7ACB\uFF0C\u5FC3\u88AB\u6B32\u671B\u7275\u7740\u8D70\uFF0C\u9677\u5165\u300C\u6C42\u300D\u7684\u6D41\u8F6C\u2014\u2014\u8FD9\u662F\u51E1\u592B\u5883\u754C\uFF0C\u5FF5\u8D77\u5373\u8FF7\u3002</p><p>\u800C\u300C\u53D1\u73B0\u6211\u60F3\u73A9\u300D\u5219\u662F\u4E00\u79CD\u89C9\u5BDF\u3002\u5F53\u6211\u4EEC\u89C2\u5BDF\u5230\u300C\u6211\u60F3\u73A9\u300D\u8FD9\u4E2A\u5FF5\u5934\u751F\u8D77\u65F6\uFF0C\u4E00\u4E2A\u300C\u53D1\u73B0\u300D\u8BA9\u5FC3\u4ECE\u89D2\u8272\u8F6C\u4E3A\u89C2\u4F17\uFF0C\u7167\u89C1\u5FF5\u5934\u7684\u751F\u706D\uFF0C\u4E0D\u518D\u8BA4\u540C\u90A3\u4E2A\u300C\u60F3\u73A9\u7684\u6211\u300D\u3002\u8FD9\u662F\u8FD4\u89C2\u81EA\u6027\uFF0C\u662F\u89C9\u7167\u7684\u521D\u663E\uFF0C\u5FF5\u8D77\u5373\u89C9\u3002</p><p>\u7985\u673A\u5C31\u5728\u8FD9\u91CC\uFF1A\u524D\u8005\u662F\u9677\u5165\u5FF5\u5934\uFF0C\u540E\u8005\u662F\u89C2\u5BDF\u8005\u610F\u8BC6\u3002\u524D\u8005\u662F\u8FF7\uFF0C\u540E\u8005\u662F\u609F\u3002</p><h2 id="\u89C9\u7167\u4E0D\u662F\u76D1\u63A7" tabindex="-1">\u89C9\u7167\u4E0D\u662F\u76D1\u63A7 <a class="header-anchor" href="#\u89C9\u7167\u4E0D\u662F\u76D1\u63A7" aria-hidden="true">#</a></h2><p>\u6709\u4EBA\u4F1A\u95EE\uFF1A\u4FEE\u884C\u662F\u4E0D\u662F\u6BCF\u4E00\u4E2A\u5FF5\u5934\u90FD\u8981\u89C9\u7167\u4E00\u4E0B\uFF1F</p><p>\u5982\u679C\u8BD5\u56FE\u5BF9\u6BCF\u4E00\u4E2A\u5FF5\u5934\u90FD\u523B\u610F\u7167\u4E00\u4E0B\uFF0C\u90A3\u662F\u5934\u8111\u7684\u518D\u9020\u4F5C\u3002\u4F60\u4EE5\u4E3A\u6709\u4E2A\u300C\u6211\u300D\u5728\u9010\u4E2A\u68C0\u67E5\u5FF5\u5934\uFF0C\u8FD9\u672C\u8EAB\u5C31\u6210\u4E86\u6700\u5927\u7684\u5984\u5FF5\uFF0C\u6BD4\u666E\u901A\u5FF5\u5934\u66F4\u7D2F\u3002\u5C31\u50CF\u6C34\u9762\u8D77\u6CE2\u7EB9\uFF0C\u4F60\u4E0D\u9700\u8981\u53BB\u6570\u6BCF\u4E00\u5708\u6D9F\u6F2A\uFF0C\u53EA\u8981\u6C34\u672C\u8EAB\u662F\u6E05\u7684\u3001\u9759\u7684\uFF0C\u6D9F\u6F2A\u81EA\u7136\u77E5\u9053\u3002</p><p>\u771F\u6B63\u7684\u89C9\u7167\u662F\u300C\u80CC\u666F\u5F0F\u7684\u89C9\u77E5\u300D\uFF0C\u4E0D\u662F\u300C\u70B9\u5BF9\u70B9\u7684\u76D1\u63A7\u300D\u3002\u597D\u6BD4\u623F\u95F4\u5F00\u706F\uFF0C\u706F\u4EAE\u4E86\uFF0C\u4E0D\u9700\u8981\u7528\u5149\u53BB\u626B\u6BCF\u4E00\u4E2A\u89D2\u843D\uFF0C\u5149\u81EA\u7136\u904D\u6EE1\u3002\u5FF5\u5934\u751F\u8D77\u65F6\uFF0C\u56E0\u4E3A\u89C9\u77E5\u672C\u5C31\u5728\uFF0C\u5B83\u4F1A\u81EA\u52A8\u77E5\u9053\uFF0C\u4E0D\u9700\u8981\u989D\u5916\u8DF3\u51FA\u6765\u300C\u7167\u4E00\u4E0B\u300D\u3002\u90A3\u4E2A\u300C\u77E5\u9053\u300D\u662F\u81EA\u7136\u53D1\u751F\u7684\uFF0C\u50CF\u955C\u5B50\u7167\u7269\uFF0C\u6765\u8005\u4E0D\u62D2\uFF0C\u53BB\u8005\u4E0D\u7559\u3002</p><h2 id="\u5984\u5FF5\u4E0E\u89C9\u7167\u7684\u5173\u7CFB" tabindex="-1">\u5984\u5FF5\u4E0E\u89C9\u7167\u7684\u5173\u7CFB <a class="header-anchor" href="#\u5984\u5FF5\u4E0E\u89C9\u7167\u7684\u5173\u7CFB" aria-hidden="true">#</a></h2><p>\u6709\u4EBA\u609F\u5230\uFF1A\u300C\u89C9\u7167\u672C\u8EAB\u76EE\u7684\u662F\u53D1\u73B0\u81EA\u5DF1\u7684\u5984\u5FF5\uFF0C\u4E00\u65E6\u53D1\u73B0\u81EA\u5DF1\u7684\u5984\u5FF5\uFF0C\u89C9\u7167\u672C\u8EAB\u5C31\u663E\u73B0\u51FA\u6765\u4E86\u3002\u6240\u4EE5\u5984\u5FF5\u548C\u89C9\u7167\u5B9E\u9645\u4E0A\u662F\u955C\u5B50\u7684\u4E00\u4F53\u4E24\u9762\u3002\u300D</p><p>\u8FD9\u4E2A\u7406\u89E3\u975E\u5E38\u63A5\u8FD1\uFF0C\u4F46\u8FD8\u5DEE\u4E00\u70B9\u3002\u51C6\u786E\u7684\u6BD4\u55BB\u662F\uFF1A\u89C9\u7167\u662F\u955C\u5B50\u672C\u8EAB\uFF0C\u5984\u5FF5\u662F\u955C\u4E2D\u7684\u5F71\u5B50\u3002\u5F71\u5B50\u79BB\u4E0D\u5F00\u955C\u5B50\uFF0C\u4F46\u955C\u5B50\u4E0D\u662F\u5F71\u5B50\u3002\u5F53\u4F60\u8FFD\u9010\u5984\u5FF5\u65F6\uFF0C\u53EA\u89C1\u5F71\u5B50\uFF0C\u5FD8\u4E86\u955C\u5B50\uFF1B\u5F53\u4F60\u300C\u53D1\u73B0\u5984\u5FF5\u300D\u65F6\uFF0C\u90A3\u4E00\u77AC\u95F4\uFF0C\u4F60\u4ECE\u5F71\u5B50\u56DE\u5934\u770B\u5230\u4E86\u955C\u5B50\u2014\u2014\u89C9\u7167\u81EA\u7136\u663E\u73B0\u3002</p><p>\u4E0D\u662F\u300C\u89C9\u7167\u53D1\u73B0\u4E86\u5984\u5FF5\u300D\uFF0C\u800C\u662F\u300C\u53D1\u73B0\u5984\u5FF5\u7684\u8FD9\u4E2A\u52A8\u4F5C\uFF0C\u5C31\u662F\u89C9\u7167\u5728\u8D77\u4F5C\u7528\u300D\u3002\u6240\u4EE5\u4F60\u8BF4\u300C\u4E00\u65E6\u53D1\u73B0\u81EA\u5DF1\u7684\u5984\u5FF5\uFF0C\u89C9\u7167\u672C\u8EAB\u5C31\u663E\u73B0\u51FA\u6765\u4E86\u300D\u2014\u2014\u5B8C\u5168\u6B63\u786E\u3002\u8FD9\u4E2A\u300C\u53D1\u73B0\u300D\u4E0D\u662F\u89C9\u7167\u7684\u7ED3\u679C\uFF0C\u5B83\u5C31\u662F\u89C9\u7167\u672C\u8EAB\u3002</p><p>\u90A3\u300C\u4E00\u4F53\u4E24\u9762\u300D\u9519\u5728\u54EA\u91CC\uFF1F\u5982\u679C\u975E\u8981\u8BF4\u662F\u4E24\u9762\uFF0C\u4F1A\u8BA9\u4EBA\u8BEF\u4EE5\u4E3A\u6709\u4E00\u4E2A\u300C\u5984\u5FF5\u9762\u300D\u548C\u300C\u89C9\u7167\u9762\u300D\u4E92\u76F8\u5207\u6362\u3002\u5B9E\u5219\u4E0D\u7136\uFF1A\u89C9\u7167\u662F\u4F53\uFF0C\u5984\u5FF5\u662F\u7528\u3002\u4F53\u7528\u4E0D\u4E8C\uFF0C\u4F46\u4F53\u4E0D\u662F\u7528\u3002\u597D\u6BD4\u624B\u638C\u63E1\u6210\u62F3\u5934\uFF0C\u62F3\u5934\uFF08\u5984\u5FF5\uFF09\u7684\u5F62\u72B6\u79BB\u4E0D\u5F00\u624B\u638C\uFF08\u89C9\u7167\uFF09\uFF0C\u4F46\u624B\u638C\u4E0D\u662F\u62F3\u5934\u3002\u677E\u5F00\u62F3\u5934\uFF0C\u624B\u638C\u4F9D\u7136\u5728\u3002</p><p>\u66F4\u6DF1\u4E00\u5C42\u8BF4\uFF1A\u5984\u5FF5\u5373\u662F\u89C9\u7167\u7684\u52A8\u6001\u663E\u76F8\u3002\u6CA1\u6709\u89C9\u7167\uFF0C\u5984\u5FF5\u65E0\u4ECE\u751F\u8D77\uFF1B\u6CA1\u6709\u5984\u5FF5\uFF0C\u89C9\u7167\u4E5F\u65E0\u4ECE\u663E\u73B0\u3002\u56E0\u4E3A\u7A7A\u6027\u9700\u8981\u7F18\u8D77\u624D\u80FD\u8BC1\u77E5\u3002\u6240\u4EE5\u516D\u7956\u8BF4\u300C\u70E6\u607C\u5373\u83E9\u63D0\u300D\u2014\u2014\u4E0D\u662F\u76F8\u540C\uFF0C\u800C\u662F\u540C\u4F53\u3002</p><h2 id="\u65E0\u5FF5\u672C\u8EAB\u4E5F\u662F\u4E00\u4E2A\u76F8" tabindex="-1">\u65E0\u5FF5\u672C\u8EAB\u4E5F\u662F\u4E00\u4E2A\u76F8 <a class="header-anchor" href="#\u65E0\u5FF5\u672C\u8EAB\u4E5F\u662F\u4E00\u4E2A\u76F8" aria-hidden="true">#</a></h2><p>\u6709\u4EBA\u95EE\uFF1A\u300C\u6211\u662F\u5FF5\u7684\u76F8\u4E5F\u662F\u5FF5\u7684\u679C\u3002\u6240\u4EE5\u65E0\u5FF5\u81EA\u7136\u65E0\u6211\uFF0C\u5BF9\u5417\uFF1F\u300D</p><p>\u8FD9\u4E2A\u95EE\u9898\u89E6\u53CA\u4E86\u66F4\u6DF1\u7684\u5C42\u6B21\u3002\u5982\u679C\u300C\u65E0\u5FF5\u300D\u662F\u6307\u5F7B\u5E95\u6B62\u606F\u5206\u522B\u6267\u7740\uFF08\u4E0D\u662F\u65AD\u706D\u7A7A\uFF0C\u800C\u662F\u300A\u516D\u7956\u575B\u7ECF\u300B\u8BF4\u7684\u300C\u4E8E\u5FF5\u800C\u65E0\u5FF5\u300D\uFF09\uFF0C\u90A3\u4E48\u300C\u6211\u300D\u7684\u9519\u89C9\u81EA\u7136\u74E6\u89E3\u3002\u56E0\u4E3A\u300C\u6211\u300D\u5FC5\u987B\u5728\u5FF5\u5FF5\u76F8\u7EED\u4E2D\u624D\u80FD\u7EF4\u6301\u5B58\u5728\u611F\u3002</p><p>\u4F46\u628A\u300C\u65E0\u5FF5\u300D\u5F53\u4F5C\u4E00\u4E2A\u76EE\u6807\u53BB\u8FBE\u6210\uFF0C\u5F97\u5230\u7684\u662F\u4E00\u79CD\u5BC2\u9759\u7684\u300C\u65E0\u5FF5\u76F8\u300D\uFF0C\u5B83\u4ECD\u7136\u662F\u5FC3\u6240\u751F\u7684\u300C\u679C\u300D\u3002\u6267\u7740\u4E8E\u6B64\uFF0C\u4FBF\u662F\u5815\u5728\u7A7A\u8FB9\uFF0C\u5982\u540C\u300A\u695E\u4E25\u7ECF\u300B\u8BF4\u7684\u300C\u5185\u5B88\u5E7D\u95F2\uFF0C\u72B9\u4E3A\u6CD5\u5C18\u5206\u522B\u5F71\u4E8B\u300D\u3002</p><p>\u6240\u4EE5\u300C\u65E0\u5FF5\u672C\u8EAB\u4E5F\u662F\u4E00\u4E2A\u76F8\u3001\u4E00\u4E2A\u679C\u300D\u2014\u2014\u5B8C\u5168\u6B63\u786E\u3002\u5B83\u4E5F\u4E0D\u662F\u4F5B\u6CD5\u8FFD\u6C42\u7684\u3002\u4F5B\u6CD5\u8FFD\u6C42\u7684\u662F\u300C\u65E0\u5FF5\u65E0\u89C9\uFF0C\u5FF5\u65F6\u89C9\u77E5\u300D\u3002</p><h2 id="\u65E0\u5FF5\u65E0\u89C9-\u80FD\u6240\u53CC\u4EA1" tabindex="-1">\u65E0\u5FF5\u65E0\u89C9\uFF0C\u80FD\u6240\u53CC\u4EA1 <a class="header-anchor" href="#\u65E0\u5FF5\u65E0\u89C9-\u80FD\u6240\u53CC\u4EA1" aria-hidden="true">#</a></h2><p>\u300C\u65E0\u5FF5\u65E0\u89C9\u300D\uFF1A\u4E0D\u662F\u65AD\u706D\uFF0C\u800C\u662F\u4E0D\u7ACB\u300C\u80FD\u89C9\u300D\u4E0E\u300C\u6240\u89C9\u300D\u3002\u6CA1\u6709\u300C\u6211\u5728\u65E0\u5FF5\u300D\u7684\u89C9\u77E5\u8005\uFF0C\u4E5F\u6CA1\u6709\u300C\u65E0\u5FF5\u300D\u8FD9\u4E2A\u88AB\u89C9\u77E5\u7684\u5BF9\u8C61\u3002\u6B64\u65F6\u300C\u89C9\u300D\u4E0E\u300C\u5FF5\u300D\u7684\u4E8C\u5143\u5BF9\u7ACB\u8131\u843D\uFF0C\u662F\u4E3A\u300C\u80FD\u6240\u53CC\u4EA1\u300D\u3002</p><p>\u300C\u5FF5\u65F6\u89C9\u77E5\u300D\uFF1A\u5FF5\u5934\u751F\u8D77\u65F6\u4E0D\u538B\u5236\u3001\u4E0D\u8DDF\u968F\uFF0C\u53EA\u662F\u7EAF\u7CB9\u7684\u77E5\u2014\u2014\u77E5\u800C\u4E0D\u4F4F\uFF0C\u77E5\u800C\u65E0\u6211\u3002\u8FD9\u5C31\u662F\u300C\u5FF5\u8D77\u4E0D\u968F\u300D\u300C\u7528\u800C\u4E0D\u67D3\u300D\u3002</p><p>\u53EF\u4EE5\u603B\u7ED3\u4E3A\u4E09\u79CD\u5883\u754C\uFF1A</p><ul><li>\u51E1\u592B\u7684\u300C\u5FF5\u300D\uFF1D\u8FF7\u6267\uFF08\u6709\u6211\uFF09</li><li>\u5916\u9053\u7684\u300C\u65E0\u5FF5\u300D\uFF1D\u538B\u5FF5\uFF08\u4ECD\u6709\u6211\uFF0C\u53EA\u662F\u8EB2\u8FDB\u7A7A\u76F8\uFF09</li><li>\u4F5B\u6CD5\u7684\u300C\u65E0\u5FF5\u65E0\u89C9\uFF0C\u5FF5\u65F6\u89C9\u77E5\u300D\uFF1D\u5FF5\u7684\u5F53\u4E0B\u5373\u7A7A\uFF0C\u89C9\u7684\u5F53\u4E0B\u65E0\u6211</li></ul><p>\u65E2\u4E0D\u6C42\u751F\u706D\u4E4B\u5916\u7684\u5BC2\u9759\uFF0C\u4E5F\u4E0D\u538C\u79BB\u5FF5\u5934\u7684\u751F\u706D\u3002</p><h2 id="\u4FEE\u884C-\u4ECE\u8FD9\u91CC\u5F00\u59CB" tabindex="-1">\u4FEE\u884C\uFF0C\u4ECE\u8FD9\u91CC\u5F00\u59CB <a class="header-anchor" href="#\u4FEE\u884C-\u4ECE\u8FD9\u91CC\u5F00\u59CB" aria-hidden="true">#</a></h2><p>\u4FEE\u884C\u7684\u6838\u5FC3\u53EA\u6709\u4E00\u4E2A\uFF1A\u7EC3\u4E60\u300C\u53D1\u73B0\u300D\uFF0C\u5E76\u5B89\u4F4F\u4E8E\u300C\u53D1\u73B0\u300D\u672C\u8EAB\u3002</p><p><strong>\u7B2C\u4E00\u6B65\uFF1A\u5148\u5B66\u4F1A\u300C\u53D1\u73B0\u300D</strong></p><p>\u6BCF\u5929\u9009\u51E0\u4EF6\u5C0F\u4E8B\u2014\u2014\u60F3\u5237\u624B\u673A\u3001\u60F3\u5403\u4E1C\u897F\u3001\u60F3\u53D1\u813E\u6C14\u2014\u2014\u5F53\u5FF5\u5934\u751F\u8D77\u65F6\uFF0C\u4E0D\u8BC4\u5224\u3001\u4E0D\u963B\u6B62\uFF0C\u53EA\u662F\u8F7B\u8F7B\u8BF4\u4E00\u58F0\uFF1A\u300C\u54E6\uFF0C\u6211\u60F3\u2026\u2026\u4E86\u3002\u300D\u8FD9\u4E00\u58F0\u300C\u54E6\u300D\u5C31\u662F\u53D1\u73B0\u3002\u5173\u952E\u662F\u4E0D\u8BD5\u56FE\u6D88\u706D\u5FF5\u5934\uFF0C\u53EA\u662F\u770B\u89C1\uFF0C\u50CF\u770B\u89C1\u4E91\u98D8\u8FC7\u3002\u300C\u4E0D\u6015\u5FF5\u8D77\uFF0C\u53EA\u6015\u89C9\u8FDF\u300D\uFF0C\u53D1\u73B0\u7684\u4E00\u77AC\uFF0C\u89C9\u5DF2\u7ECF\u5728\u4E86\u3002</p><p><strong>\u7B2C\u4E8C\u6B65\uFF1A\u8BA9\u89C9\u7167\u8FDE\u6210\u7247</strong></p><p>\u5750\u7985\u6216\u884C\u7985\u65F6\uFF0C\u4EFB\u4F55\u5FF5\u5934\u8D77\u6765\u90FD\u53EA\u662F\u77E5\u9053\uFF0C\u4E0D\u8DDF\u7740\u8DD1\uFF0C\u4E5F\u4E0D\u538B\u5B83\u3002\u65E5\u5E38\u4E2D\uFF0C\u5DE5\u4F5C\u65F6\u7A81\u7136\u60F3\u95F2\u804A\u2014\u2014\u53D1\u73B0\uFF1B\u751F\u6C14\u4E86\u2014\u2014\u53D1\u73B0\uFF1B\u5F97\u610F\u4E86\u2014\u2014\u53D1\u73B0\u3002\u4E00\u5929\u51E0\u5341\u6B21\u3001\u4E0A\u767E\u6B21\u3002\u4E45\u800C\u4E45\u4E4B\uFF0C\u300C\u53D1\u73B0\u300D\u4E0D\u518D\u9700\u8981\u7528\u529B\uFF0C\u53D8\u6210\u81EA\u7136\u7684\u5149\u660E\u3002</p><p>\u4E0D\u8FFD\u6C42\u300C\u65E0\u5FF5\u300D\uFF0C\u53EA\u8FFD\u6C42\u300C\u5FF5\u5FF5\u89C9\u77E5\u300D\u3002\u4E45\u800C\u4E45\u4E4B\uFF0C\u300C\u53D1\u73B0\u300D\u4E0D\u518D\u9700\u8981\u7528\u529B\uFF0C\u53D8\u6210\u81EA\u7136\u7684\u5149\u660E\u3002</p><p><strong>\u7B2C\u4E09\u6B65\uFF1A\u653E\u4E0B\u300C\u53D1\u73B0\u8005\u300D</strong></p><p>\u5F53\u4F60\u719F\u7EC3\u5230\u300C\u53D1\u73B0\u300D\u5DF2\u6210\u4E60\u60EF\uFF0C\u4F1A\u53D1\u73B0\u90A3\u4E2A\u300C\u80FD\u53D1\u73B0\u7684\u6211\u300D\u548C\u300C\u88AB\u53D1\u73B0\u7684\u5FF5\u5934\u300D\u5176\u5B9E\u662F\u4E00\u4E2A\u3002\u8C01\u5728\u53D1\u73B0\uFF1F\u8C01\u88AB\u53D1\u73B0\u4E86\uFF1F\u4E00\u53C2\uFF0C\u80FD\u6240\u53CC\u4EA1\u3002</p><p>\u8FD9\u65F6\u5019\u300C\u6211\u60F3\u73A9\u300D\u4F9D\u7136\u4F1A\u751F\u8D77\uFF0C\u4F46\u4F60\u5DF2\u7ECF\u4E0D\u6025\u7740\u628A\u5B83\u5F53\u6210\u654C\u4EBA\u3002\u73A9\u5C31\u73A9\u4E86\uFF0C\u4E0D\u73A9\u4E5F\u884C\u2014\u2014\u5FC3\u65E0\u6302\u788D\u3002\u5403\u996D\u65F6\u5403\u996D\uFF0C\u73A9\u65F6\u73A9\uFF0C\u800C\u59CB\u7EC8\u77E5\u9053\uFF1A\u6CA1\u6709\u90A3\u4E2A\u300C\u6211\u300D\u5728\u771F\u6B63\u62E5\u6709\u4EC0\u4E48\u3002</p><p>\u300C\u6070\u6070\u7528\u5FC3\u65F6\uFF0C\u6070\u6070\u65E0\u5FC3\u7528\u300D\uFF0C\u5230\u8FD9\u4E00\u6B65\uFF0C\u6CA1\u6709\u4FEE\u884C\u76F8\uFF0C\u53EA\u662F\u5E73\u5E38\u5FC3\u3002</p><h2 id="\u603B\u7ED3" tabindex="-1">\u603B\u7ED3 <a class="header-anchor" href="#\u603B\u7ED3" aria-hidden="true">#</a></h2><p>\u4FEE\u884C\u7684\u9053\u7406\uFF0C\u8BF4\u5230\u5E95\u4E0D\u8FC7\u662F\u51E0\u53E5\u8BDD\uFF1A</p><p><strong>\u89C9\u7167\u4E0D\u662F\u76EE\u6807</strong>\uFF0C\u5B83\u662F\u6211\u4EEC\u672C\u6709\u7684\u72B6\u6001\u3002\u5F53\u4F60\u4E0D\u518D\u628A\u5B83\u5F53\u4F5C\u4E00\u9879\u300C\u4EFB\u52A1\u300D\uFF0C\u4E0D\u518D\u89C9\u5F97\u300C\u6211\u5FC5\u987B\u53D1\u73B0\u5984\u5FF5\u3001\u6211\u8981\u8BA9\u955C\u5B50\u53D8\u4EAE\u300D\uFF0C\u800C\u662F\u8BA9\u5B83\u50CF\u547C\u5438\u3001\u50CF\u6D41\u6C34\u4E00\u6837\u81EA\u7136\u53D1\u751F\u65F6\uFF0C\u529F\u592B\u624D\u7B97\u771F\u6B63\u4E0A\u8DEF\u3002</p><p><strong>\u5984\u5FF5\u5373\u662F\u89C9\u7167\u7684\u663E\u76F8</strong>\uFF0C\u6CA1\u6709\u89C9\u7167\uFF0C\u5984\u5FF5\u65E0\u4ECE\u751F\u8D77\uFF1B\u6CA1\u6709\u5984\u5FF5\uFF0C\u89C9\u7167\u4E5F\u65E0\u4ECE\u663E\u73B0\u3002\u70E6\u607C\u5373\u83E9\u63D0\uFF0C\u4E0D\u662F\u76F8\u540C\uFF0C\u800C\u662F\u540C\u4F53\u3002</p><p><strong>\u4FEE\u884C\u662F\u81EA\u7136\u7684\u8FC7\u7A0B</strong>\u3002\u4E0D\u662F\u53BB\u6C42\u955C\u5B50\uFF0C\u800C\u662F\u53BB\u8BA4\u5F97\u5F71\u5B50\u3002\u8BA4\u5F97\u4E00\u4E2A\u5F71\u5B50\uFF0C\u955C\u5B50\u5C31\u4EAE\u4E00\u5206\u3002\u4F46\u83AB\u7BA1\u955C\u5B50\u4EAE\u4E0D\u4EAE\uFF0C\u53EA\u8001\u8001\u5B9E\u5B9E\u5730\u300C\u53D1\u73B0\u300D\u3002</p><p>\u5230\u6700\u540E\uFF0C\u8FDE\u300C\u53D1\u73B0\u300D\u8FD9\u4E2A\u52A8\u4F5C\u4E5F\u653E\u4E0B\uFF0C\u53EA\u662F\u660E\u660E\u4E86\u4E86\uFF0C\u65E0\u53D6\u65E0\u820D\u3002\u90A3\u65F6\u5019\u4F60\u4F1A\u7B11\u7740\u8BF4\uFF1A\u539F\u6765\u4ECE\u6765\u6CA1\u6709\u300C\u955C\u5B50\u300D\u548C\u300C\u5F71\u5B50\u300D\u7684\u5206\u522B\uFF0C\u53EA\u662F\u81EA\u5DF1\u7684\u4E00\u573A\u6E38\u620F\u3002\u5230\u90A3\u65F6\uFF0C\u73A9\u4E5F\u597D\uFF0C\u4E0D\u73A9\u4E5F\u597D\uFF0C\u90FD\u662F\u81EA\u5728\u3002</p><blockquote><p>\u4E0B\u6B21\u4F60\u5FC3\u91CC\u5192\u51FA\u300C\u597D\u60F3\u73A9\u6E38\u620F\u300D\u65F6\uFF0C\u505C\u4E09\u79D2\u5728\u5FC3\u91CC\u95EE\u81EA\u5DF1\uFF1A\u300C\u662F\u8C01\u77E5\u9053\u300E\u6211\u60F3\u73A9\u300F\uFF1F\u300D\u7B54\u6848\u4E0D\u662F\u540D\u5B57\u3001\u4E0D\u662F\u5934\u8111\uFF0C\u662F\u90A3\u4E2A\u7EAF\u7CB9\u7684\u300C\u77E5\u300D\u3002\u56DE\u5230\u90A3\u4E2A\u77E5\uFF0C\u54EA\u6015\u53EA\u6709\u4E00\u79D2\u3002\u7136\u540E\u8BE5\u73A9\u8FD8\u662F\u4E0D\u8BE5\u73A9\uFF0C\u968F\u4F60\uFF0C\u4F46\u90A3\u4E00\u79D2\u5C31\u662F\u4FEE\u884C\u3002</p></blockquote><p>\u4FEE\u884C\u53EA\u662F\u8BA4\u51FA\u2014\u2014\u672C\u65E0\u5FF5\u53EF\u706D\uFF0C\u672C\u65E0\u89C9\u53EF\u5F97\u3002\u5FF5\u4E0E\u65E0\u5FF5\uFF0C\u90FD\u662F\u89C9\u7684\u5149\u5F71\u3002\u8BA4\u5F97\u8FD9\u4E2A\uFF0C\u4FBF\u662F\u65E0\u4FEE\u4E4B\u4FEE\u3002</p>',49),n=[i];function l(s,d,h,o,c,u){return p(),a("div",null,n)}const f=e(r,[["render",l]]);export{g as __pageData,f as default};
